import logging
import sys
from functools import wraps
from typing import Any, Callable, Optional

# Configure logging
logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s - %(name)s - %(levelname)s - %(message)s',
    handlers=[
        logging.StreamHandler(sys.stdout),
        logging.FileHandler('service.log')
    ]
)

logger = logging.getLogger(__name__)

def log_errors(func: Callable) -> Callable:
    """Decorator to log function errors and execution"""
    @wraps(func)
    def wrapper(*args, **kwargs):
        try:
            logger.info(f"Executing {func.__name__} with args={args}, kwargs={kwargs}")
            result = func(*args, **kwargs)
            logger.info(f"Successfully completed {func.__name__}")
            return result
        except Exception as e:
            logger.error(f"Error in {func.__name__}: {str(e)}", exc_info=True)
            raise
    return wrapper

class ServiceError(Exception):
    """Custom service exception"""
    def __init__(self, message: str, error_code: Optional[str] = None):
        self.message = message
        self.error_code = error_code
        super().__init__(self.message)
        logger.error(f"ServiceError: {message} (Code: {error_code})")

def handle_service_error(func: Callable) -> Callable:
    """Decorator to handle and log service errors"""
    @wraps(func)
    def wrapper(*args, **kwargs):
        try:
            return func(*args, **kwargs)
        except ServiceError:
            raise
        except Exception as e:
            error_msg = f"Unexpected error in {func.__name__}: {str(e)}"
            logger.critical(error_msg, exc_info=True)
            raise ServiceError(error_msg, "UNEXPECTED_ERROR")
    return wrapper

def log_performance(func: Callable) -> Callable:
    """Decorator to log function performance"""
    @wraps(func)
    def wrapper(*args, **kwargs):
        import time
        start_time = time.time()
        try:
            result = func(*args, **kwargs)
            execution_time = time.time() - start_time
            logger.info(f"{func.__name__} executed in {execution_time:.3f}s")
            return result
        except Exception as e:
            execution_time = time.time() - start_time
            logger.warning(f"{func.__name__} failed after {execution_time:.3f}s")
            raise
    return wrapper

